INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '63bc6543-7de8-4b63-a3d8-9ac41a71b645',
  '00000000-0000-0000-0000-000000000001',
  $escape$Deno KV — Generics and Type Inference Without the Boilerplate$escape$,
  $escape$Deno ships TypeScript as a first-class runtime — no tsconfig, no ts-node, no build step. That means type safety is structural, not bolted on. Deno's built-in APIs are fully generic: `Deno.Kv.get<T>()` returns `Deno.KvEntryMaybe<T>`, so the inferred type flows through your entire read path without a cast.

Where most runtimes force you to `JSON.parse()` and assert types manually, Deno KV lets you bind a concrete type at the call site. The generic propagates through `.value`, giving you `T | null` rather than `unknown`. Pair this with a thin wrapper and you get a typed data layer with zero schemas or validators at the persistence boundary.

`deno check` runs the TypeScript compiler in isolation — no execution — so you can gate CI on type correctness before any code runs. Static analysis catches `user.email` access on a potentially-null value at compile time, not at runtime in production. Generics across Deno's `fetch`, `KV`, and `serve` APIs follow the same pattern: type once at the boundary, infer everywhere downstream.$escape$,
  $escape$const kv = await Deno.openKv();

interface User { id: string; name: string; email: string; }

async function getTyped<T>(key: Deno.KvKey): Promise<T | null> {
  const entry = await kv.get<T>(key);
  return entry.value; // T | null — no cast, no `as`
}

async function setTyped<T>(key: Deno.KvKey, value: T): Promise<void> {
  await kv.set(key, value);
}

await setTyped<User>(["users", "u1"], { id: "u1", name: "Ada", email: "ada@example.com" });
const user = await getTyped<User>(["users", "u1"]);
if (user) console.log(user.email); // fully typed, no assertion needed$escape$,
  $escape$typescript$escape$,
