INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6abc1735-59e1-411c-b5c7-df147511f249',
  '00000000-0000-0000-0000-000000000001',
  $escape$Deno Error Handling — Bridging Thrown Errors and Result Types$escape$,
  $escape$Deno's built-in APIs throw typed errors — `Deno.errors.NotFound`, `Deno.errors.PermissionDenied`, `Deno.errors.ConnectionRefused` — unlike Node's callback-style errno codes. This gives you precise catch blocks, but exceptions still break control flow silently.

The Result pattern (a discriminated union `{ ok: true; value: T } | { ok: false; error: E }`) makes error paths explicit in the type signature. The key Deno idiom: wrap throwing stdlib calls in a thin Result factory — catch known `Deno.errors.*` subtypes and convert them to `{ ok: false }`, then re-throw anything unexpected so permission errors still surface loudly.

Propagation works best with early returns: check `if (!result.ok) return result` up the call stack instead of nesting try/catch. For Deno CLI tools, convert back to exceptions at the entry point with `Deno.exit(1)` after logging. For HTTP handlers (`Deno.serve`, Hono, Oak), map the error discriminant to a status code before returning a `Response`.

Avoid catch-all swallowing — `Deno.errors.BadResource` and `Deno.errors.Interrupted` signal very different failure modes and deserve distinct handling.$escape$,
  $escape$type Result<T, E = Error> = { ok: true; value: T } | { ok: false; error: E };

async function readConfig(path: string): Promise<Result<string>> {
  try {
    const text = await Deno.readTextFile(path);
    return { ok: true, value: text };
  } catch (e) {
    if (e instanceof Deno.errors.NotFound) {
      return { ok: false, error: new Error(`Config not found: ${path}`) };
    }
    throw e; // re-throw unexpected errors (e.g. PermissionDenied)
  }
}

const result = await readConfig("./config.json");
if (!result.ok) { console.error(result.error.message); Deno.exit(1); }
console.log(result.value);$escape$,
  $escape$typescript$escape$,
