INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '861491df-caec-427d-a35f-d7c866a95d3f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Deno's Standard Library — What's Built In vs What You Still Need npm For$escape$,
  $escape$Deno ships with a rich standard library at `jsr:@std/` that covers most day-to-day needs without touching npm. For file I/O, use `Deno.readTextFile` / `Deno.writeTextFile` — no `fs` import needed. HTTP servers? `Deno.serve()` is stable and built-in since Deno 1.35. Need parsing? `@std/csv`, `@std/toml`, `@std/yaml`, and `@std/jsonc` are all available. Cryptography is covered by the Web Crypto API (`crypto.subtle`) plus `@std/crypto` for hashing utilities like `encodeHex`. Date formatting, UUIDs (`@std/uuid`), path manipulation (`@std/path`), and assertion utilities for testing (`@std/assert`) round out the core.

Where the stdlib still falls short: database drivers (reach for `npm:postgres` or `npm:drizzle-orm`), JWT handling (`npm:jose`), email sending, and any cloud SDK. Deno's `npm:` specifier makes these drop-in, but they bypass Deno's permission model — always audit what you're pulling in. The rule of thumb: prefer `jsr:@std/` first, then `jsr:` ecosystem packages, npm as a last resort.$escape$,
  $escape$// Built-in: no imports needed for HTTP
Deno.serve({ port: 8000 }, (_req) => new Response("Hello"));

// JSR stdlib: hashing, path, UUID
import { encodeHex } from "jsr:@std/encoding/hex";
import { join } from "jsr:@std/path";
import { v4 } from "jsr:@std/uuid";

const hash = encodeHex(await crypto.subtle.digest("SHA-256", new TextEncoder().encode("deno")));
const filePath = join(Deno.cwd(), "data", `${v4.generate()}.txt`);
await Deno.writeTextFile(filePath, hash);

// npm as last resort — loses Deno sandbox guarantees
import { createTransport } from "npm:nodemailer";$escape$,
  $escape$typescript$escape$,
