INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '78713ffc-7878-4837-a4fd-cb4b559a2fde',
  '00000000-0000-0000-0000-000000000001',
  $escape$Deno's Built-in Test Runner — No Jest, No Config, Just `deno test`$escape$,
  $escape$Deno ships a first-class test runner with zero configuration. You define tests using `Deno.test()`, which accepts a name and an async function. Assertions come from the standard library — `@std/assert` — giving you `assertEquals`, `assertThrows`, `assertRejects`, and more without any third-party install.

Tests run in isolation by default. Each `Deno.test()` call gets its own sanitizer checks: Deno will fail a test if it leaks async ops or spawns unresolved promises — catching bugs that Jest silently misses.

Use `deno test --watch` during development for instant re-runs on file changes. Scope runs with `deno test path/to/file_test.ts` or filter by name with `--filter`. For grouped behavior, nest tests using `t.step()` inside a parent `Deno.test` — Deno's subtests give you hierarchical output without a `describe` wrapper.

Permissions apply to tests too: `deno test --allow-net` is required if your unit under test touches the network, keeping your test surface explicit and auditable.$escape$,
  $escape$import { assertEquals, assertRejects } from "jsr:@std/assert";

Deno.test("parseVersion returns major.minor tuple", () => {
  assertEquals(parseVersion("1.2.3"), [1, 2]);
});

Deno.test("fetchUser rejects on 404", async () => {
  await assertRejects(
    () => fetchUser("unknown"),
    Error,
    "User not found",
  );
});

Deno.test("grouped: config loading", async (t) => {
  await t.step("reads from env", () => { /* ... */ });
  await t.step("falls back to defaults", () => { /* ... */ });
});$escape$,
