INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '86311da7-38dc-44db-b76e-826eb4ed866f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Deno's Built-In Linter and Formatter — Zero Config, Maximum Consistency$escape$,
  $escape$Deno ships `deno lint` and `deno fmt` as first-class CLI tools — no ESLint config, no Prettier setup, no `node_modules`. Both run on the same V8-backed runtime, making them fast and predictable across machines.

`deno lint` enforces a curated rule set (based on `eslint` and `typescript-eslint`) with Deno-specific rules like `no-window-prefix` (prefer `globalThis` over `window`) and `ban-untagged-todo`. Run `deno lint --rules` to inspect every active rule.

`deno fmt` uses `dprint` under the hood and is opinionated by design — no semicolons debate, no tab-vs-space wars. Configure deviations only when necessary via `deno.json`:

```json
{ "fmt": { "useTabs": false, "lineWidth": 100, "indentWidth": 2 } }
```

For CI, combine both with `--check` to fail fast without mutating files. Pair with `deno task lint` and `deno task fmt` entries in `deno.json` to give teammates a single entry point. Avoid reaching for external tooling — Deno's built-ins are already version-locked to the runtime.$escape$,
  $escape$// deno.json — single source of truth for lint + fmt config
{
  "tasks": {
    "lint": "deno lint",
    "fmt": "deno fmt --check"
  },
  "lint": {
    "rules": {
      "exclude": ["no-explicit-any"]
    }
  },
  "fmt": {
    "useTabs": false,
    "lineWidth": 100,
    "indentWidth": 2,
    "singleQuote": false
  }
}$escape$,
  $escape$javascript$escape$,
