INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd05c7430-335a-43ba-89eb-8fa5d4dbffe8',
  '00000000-0000-0000-0000-000000000001',
  $escape$Deno Security — Permissions, Injection Prevention, and Supply Chain Integrity$escape$,
  $escape$Deno's security model starts at process launch: every dangerous capability requires an explicit `--allow-*` flag. But the runtime API goes further — `Deno.permissions.query()` lets you gate sensitive code paths at runtime, and `Deno.permissions.revoke()` enforces least-privilege by dropping rights after a one-time use.

For injection prevention, never interpolate user input into shell strings. `Deno.Command` takes an `args` array that bypasses the shell entirely — no escaping required, no injection surface. This is the idiomatic Deno replacement for `child_process.exec`.

For dependency integrity, Deno's lockfile (`deno.lock`) records cryptographic hashes of every remote module. Run with `--frozen` in CI to reject any hash mismatch — this catches both accidental drift and supply chain tampering. Combine with an import map to pin specifiers to audited versions, eliminating floating URLs. Unlike `npm audit`, Deno doesn't yet have a built-in CVE scanner, but `deno outdated` surfaces stale deps, and tools like `deno_audit` can integrate with OSV for vulnerability lookups.$escape$,
  $escape$// Runtime permission check before sensitive op
const status = await Deno.permissions.query({ name: "net", host: "api.internal" });
if (status.state !== "granted") throw new Error("Net access not granted");

// Injection-safe subprocess — args never touch a shell
const cmd = new Deno.Command("git", {
  args: ["log", "--oneline", userProvidedRef], // no shell interpolation
  stdout: "piped",
  stderr: "null",
});
const { stdout } = await cmd.output();

// Drop read access after one-time secret load (least privilege)
await Deno.permissions.revoke({ name: "read", path: "/run/secrets" });$escape$,
  $escape$typescript$escape$,
