INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '00a99f3d-ba2d-4f9f-aec3-99d51517e0c4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Deno compile — Ship a Single Binary with Zero Runtime Dependencies$escape$,
  $escape$`deno compile` bundles your script, all remote imports, and the Deno runtime into a single executable — no npm install, no node_modules, no Deno on the host. The output is ~80–100 MB (V8 is not small), but that's the only artifact you ship.

For containers, skip the official `denoland/deno` image entirely. Cross-compile to `x86_64-unknown-linux-gnu` locally, then copy the binary into `gcr.io/distroless/cc-debian12` — a ~20 MB base with just glibc. Final image lands around 120 MB versus the ~200 MB `denoland/deno` + source approach.

Permissions are baked in at compile time via `--allow-net`, `--allow-env`, etc. — no flags needed at runtime. For ARM deploys (e.g., AWS Graviton), target `aarch64-unknown-linux-gnu` from your local machine. Use `--no-terminal` on Windows targets to suppress the console window.

One hard limit: `deno compile` does not support `npm:` specifiers that rely on native Node addons — those still require the full Deno runtime on the host.$escape$,
  $escape$# Cross-compile from Mac/Windows for Linux
deno compile \
  --target x86_64-unknown-linux-gnu \
  --allow-net --allow-env \
  --output server \
  main.ts

# Dockerfile — zero Deno runtime needed at deploy
FROM gcr.io/distroless/cc-debian12
COPY server /server
EXPOSE 8000
ENTRYPOINT ["/server"]$escape$,
  $escape$bash$escape$,
